        const shakeDuration = 500; // milliseconds
        const shakeMagnitude = 10; // pixels
        let startTime = Date.now();

        function shake() {
            const elapsed = Date.now() - startTime;
            if (elapsed < shakeDuration) {
                const x = (Math.random() * shakeMagnitude) - (shakeMagnitude / 2);
